document.querySelector("form").addEventListener("submit", async (e) => {
  e.preventDefault();

  const data = {
    name: document.querySelector("input[placeholder='Full Name']").value,
    email: document.querySelector("input[placeholder='Email']").value,
    password: document.querySelector("input[placeholder='Password']").value,
    phone: document.querySelector("input[placeholder='Phone Number']").value,
    gender: document.querySelector("select:nth-of-type(2)").value,
    room_type: document.querySelector("select:nth-of-type(1)").value
  };

  const res = await fetch("http://localhost:5000/signup", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data)
  });

  const msg = await res.text();
  alert(msg);

  // Optional: Reset form after signup
  document.querySelector("form").reset();
});
